function showImage(index) {
    currentIndex = index;
    mainImage.src = thumbnails[index].src;
    document.querySelector('.thumbnail.active')?.classList.remove('active');
    thumbnails[index].classList.add('active');
}

document.addEventListener('keydown', (e) => {
    if (e.key === 'ArrowLeft') navigate(-1);
    if (e.key === 'ArrowRight') navigate(1);
});

const observer = new IntersectionObserver((entries) => {
    entries.forEach(entry => {
        if (entry.isIntersecting) {
            entry.target.classList.add('active');
            if (entry.target.classList.contains('stat-card')) {
                animateCounter(entry.target);
            }
        }
    });
}, { threshold: 0.1, rootMargin: '0px 0px -100px 0px' });

document.querySelectorAll('.reveal, .feature-card, .stat-card')
    .forEach(el => observer.observe(el));

function animateCounter(element) {
    const target = parseInt(element.dataset.count);
    const numEl = element.querySelector('.stat-number');
    let current = 0;
    const increment = target / (2000 / 16);
    function update() {
        current += increment;
        if (current < target) {
            numEl.textContent = Math.floor(current);
            requestAnimationFrame(update);
        } else numEl.textContent = target;
    }
    requestAnimationFrame(update);
}

// MODAL
function openModal(id) {
    document.getElementById(id).classList.add('active');
    document.body.style.overflow = 'hidden';
}
document.addEventListener('keydown', e => {
    if (e.key === 'Escape') closeAllModals();
});

// DROPDOWN: close on outside click
document.addEventListener('click', e => {
    if (!e.target.closest('.dropdown'))
        document.querySelectorAll('.dropdown-menu.active')
            .forEach(m => m.classList.remove('active'));
});

// TABS: event delegation + keyboard
tabList.addEventListener('click', e => {
    if (e.target.matches('.tab')) activateTab(e.target);
});
tabList.addEventListener('keydown', e => {
    if (e.key === 'ArrowRight') focusNextTab();
    if (e.key === 'ArrowLeft') focusPrevTab();
});

// ACCORDION: toggle with delegation
accordion.addEventListener('click', e => {
    const header = e.target.closest('.accordion-header');
    if (header) {
        header.classList.toggle('active');
        header.nextElementSibling.classList.toggle('active');
    }
});
